INSERT INTO public.email_templates (template_type, template_name, subject, html_content, is_default)
VALUES
  ('live_reminder_tu', 'Rappel de live (tu)', '📺 Rappel : Live "{{live_title}}" aujourd''hui – {{training_name}}',
   E'Bonjour {{first_name}},\n\nPour rappel, tu as un live collectif prévu aujourd''hui dans le cadre de la formation <strong>"{{training_name}}"</strong> :\n\n<ul>\n<li><strong>{{live_title}}</strong></li>\n<li>📅 {{live_date}} à {{live_time}}</li>\n</ul>\n\n{{#meeting_url}}<p><a href="{{meeting_url}}" style="display: inline-block; background-color: #e6bc00; color: #1a1a1a; padding: 12px 24px; text-decoration: none; border-radius: 6px; font-weight: bold;">Rejoindre le live</a></p>{{/meeting_url}}\n\nTa présence est importante pour profiter pleinement de ce moment d''échange.\n\nÀ tout à l''heure !', true),

  ('live_reminder_vous', 'Rappel de live (vous)', '📺 Rappel : Live "{{live_title}}" aujourd''hui – {{training_name}}',
   E'Bonjour {{first_name}},\n\nPour rappel, vous avez un live collectif prévu aujourd''hui dans le cadre de la formation <strong>"{{training_name}}"</strong> :\n\n<ul>\n<li><strong>{{live_title}}</strong></li>\n<li>📅 {{live_date}} à {{live_time}}</li>\n</ul>\n\n{{#meeting_url}}<p><a href="{{meeting_url}}" style="display: inline-block; background-color: #e6bc00; color: #1a1a1a; padding: 12px 24px; text-decoration: none; border-radius: 6px; font-weight: bold;">Rejoindre le live</a></p>{{/meeting_url}}\n\nVotre présence est importante pour profiter pleinement de ce moment d''échange.\n\nÀ tout à l''heure !', true);